import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'csirt-n8n-prod',
  apiKey: process.env.VEX_API_KEY
});

const result = await vex.evaluate({
  workflow: {
    name: 'n8n Threat Triage',
    trigger: 'ai-agent-output'
  },
  input: {
    threatIntel: $input.ai.output,
    iocs: extractIOCs($input.ai.output),
    action: $input.nextNode.name
  },
  policy: {
    block: ['leak:pii', 'leak:ioc', 'action:critical'],
    require: ['human:approval'],
    validate: ['cve:match']
  }
});

if (!result.pass) {
  throw new Error(`Vex blocked: ${result.reason}`);
}

return { verified: true, data: $input.ai.output };

const policyCheck = await vex.evaluate({
  input: {
    toolParams: $input.ai.tools[0].parameters,
    workflowContext: $json
  },
  policy: {
    block: ['secret:api-key', 'secret:token'],
    redact: ['credential'],
    log: 'audit:credential-exposure-attempt'
  }
});

if (policyCheck.secretsFound) {
  $input.ai.tools[0].parameters = policyCheck.redacted;
  await sendAlert('Potential credential exposure detected');
}

const actionEval = await vex.evaluate({
  input: {
    proposedAction: $input.ai.action,
    severity: $input.threatScore,
    target: $input.affectedSystems
  },
  policy: {
    require: ['human:approval'],
    threshold: {
      severity: 'critical',
      autoBlock: true
    },
    notify: ['slack:soc-team', 'email:incident-lead']
  }
});

if (actionEval.requiresApproval) {
  const approval = await waitForHumanApproval();
  if (!approval.granted) {
    return { status: 'blocked', reason: 'human approval denied' };
  }
}

// Proceed to execute action
return { approved: true };
